import React, { useEffect, useState, useCallback } from 'react';
import { useSearchParams, Link } from 'react-router-dom';
import axios from 'axios';
import InfiniteScroll from 'react-infinite-scroll-component';
import { Helmet } from 'react-helmet-async';
import Skeleton from 'react-loading-skeleton';
import { useCart } from '../context/CartContext';
import ProductCard from '../components/ProductCard';
import { unwrapProductListResponse, apiMessage } from '../lib/api';

const PAGE_SIZE = 12;

const Products = () => {
  const [searchParams, setSearchParams] = useSearchParams();
  const [items, setItems] = useState([]);
  const [page, setPage] = useState(1);
  const [totalPages, setTotalPages] = useState(1);
  const [loading, setLoading] = useState(true);
  const [fetchError, setFetchError] = useState(null);
  const [sortBy, setSortBy] = useState(searchParams.get('sort') || 'newest');

  const cat = searchParams.get('cat') || 'all';
  const { addToCart } = useCart();

  const loadPage = useCallback(
    async (nextPage, reset) => {
      setFetchError(null);
      if (reset) setLoading(true);
      try {
        const params = new URLSearchParams();
        if (cat && cat !== 'all') params.set('category', cat);
        params.set('page', String(nextPage));
        params.set('limit', String(PAGE_SIZE));
        if (sortBy) params.set('sort', sortBy);
        const response = await axios.get(`/api/products?${params.toString()}`);
        const { products, totalPages: tp, currentPage } = unwrapProductListResponse(response);
        if (reset) {
          setItems(products);
        } else {
          setItems((prev) => {
            const ids = new Set(prev.map((p) => String(p._id)));
            const merged = [...prev];
            for (const p of products) {
              if (!ids.has(String(p._id))) merged.push(p);
            }
            return merged;
          });
        }
        setTotalPages(tp || 1);
        setPage(currentPage || nextPage);
      } catch (error) {
        console.error(error);
        const msg =
          error.code === 'ERR_NETWORK' || error.message?.includes('Network Error')
            ? 'Cannot reach the API. Is the backend running on port 5000?'
            : apiMessage(error, 'Failed to load products');
        setFetchError(msg);
        if (reset) setItems([]);
      } finally {
        setLoading(false);
      }
    },
    [cat, sortBy]
  );

  useEffect(() => {
    setPage(1);
    loadPage(1, true);
  }, [cat, sortBy, loadPage]);

  const hasMore = page < totalPages;

  const fetchMore = () => {
    if (!hasMore || loading) return;
    loadPage(page + 1, false);
  };

  const handleCategoryChange = (category) => {
    const next = new URLSearchParams(searchParams);
    if (category === 'all') next.delete('cat');
    else next.set('cat', category);
    setSearchParams(next);
  };

  const handleSortChange = (sort) => {
    setSortBy(sort);
    const next = new URLSearchParams(searchParams);
    next.set('sort', sort);
    setSearchParams(next);
  };

  const handleAddToCart = async (product) => {
    await addToCart(product, 1);
  };

  return (
    <>
      <Helmet>
        <title>Shop | Nova Shop</title>
      </Helmet>
      <header className="page-header">
        <div className="container">
          <h1>Shop all products</h1>
          <ol className="breadcrumb" aria-label="Breadcrumb">
            <li>
              <Link to="/">Home</Link>
            </li>
            <li className="active">Shop</li>
          </ol>
        </div>
      </header>

      <main className="section" id="main-content">
        <div className="container">
          <div className="categories-strip" role="group" style={{ marginBottom: '2rem' }}>
            {['all', 'electronics', 'fashion', 'home', 'beauty', 'sports'].map((c) => (
              <button
                key={c}
                type="button"
                className={`category-chip ${cat === c ? 'active' : ''}`}
                onClick={() => handleCategoryChange(c)}
              >
                {c === 'all'
                  ? 'All'
                  : c === 'electronics'
                    ? '📱 Electronics'
                    : c === 'fashion'
                      ? '👗 Fashion'
                      : c === 'home'
                        ? '🏡 Home'
                        : c === 'beauty'
                          ? '💄 Beauty'
                          : '⚽ Sports'}
              </button>
            ))}
          </div>

          {fetchError && (
            <div className="api-error-banner" role="alert">
              <p>
                <strong>Products could not be loaded.</strong> {fetchError}
              </p>
              <button type="button" className="btn btn-outline btn-sm" onClick={() => loadPage(1, true)}>
                Retry
              </button>
            </div>
          )}

          <div className="shop-toolbar">
            <p className="results-count">Showing {items.length} products</p>
            <div className="toolbar-right">
              <select
                className="sort-select"
                value={sortBy}
                onChange={(e) => handleSortChange(e.target.value)}
              >
                <option value="newest">Newest</option>
                <option value="popular">Popular</option>
                <option value="price-asc">Price: Low to High</option>
                <option value="price-desc">Price: High to Low</option>
                <option value="rating">Rating</option>
                <option value="name">Name A–Z</option>
              </select>
            </div>
          </div>

          {loading && items.length === 0 ? (
            <div className="products-grid">
              {[1, 2, 3, 4, 5, 6].map((i) => (
                <div key={i} className="product-card">
                  <Skeleton height={220} />
                  <Skeleton count={2} style={{ marginTop: 12 }} />
                </div>
              ))}
            </div>
          ) : fetchError && items.length === 0 ? (
            <p className="empty-products-hint empty-products-hint--muted">Fix the connection and retry.</p>
          ) : items.length === 0 ? (
            <div className="empty-products-hint">
              <p>No products match your filters.</p>
            </div>
          ) : (
            <InfiniteScroll
              dataLength={items.length}
              next={fetchMore}
              hasMore={hasMore}
              loader={
                <p style={{ textAlign: 'center', padding: '1rem' }}>Loading more…</p>
              }
              style={{ overflow: 'visible' }}
            >
              <div className="products-grid" role="list">
                {items.map((product) => (
                  <ProductCard
                    key={product._id}
                    product={product}
                    onAddToCart={handleAddToCart}
                  />
                ))}
              </div>
            </InfiniteScroll>
          )}
        </div>
      </main>
    </>
  );
};

export default Products;
